/**
 * sarvamAgent.js
 *
 * Sarvam AI-powered Web3 DeFi Intent Parser
 *
 * Accepts a natural-language user prompt and returns a strictly typed JSON object:
 *   { action: string, amount: string | number, token: string }
 *
 * Uses the Sarvam AI REST API (OpenAI-compatible chat completions endpoint).
 * The `sarvamai` npm package ships only speech / translation / document APIs;
 * the LLM chat interface is accessed directly via the REST endpoint below.
 *
 * Required env variable (Vite project):
 *   VITE_SARVAM_API_KEY  ΓÇö your Sarvam AI subscription key
 */

// ΓöÇΓöÇΓöÇ Constants ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

const SARVAM_API_BASE = "/sarvam-api";
const SARVAM_CHAT_ENDPOINT = `${SARVAM_API_BASE}/v1/chat/completions`;

/**
 * Default model served by Sarvam AI's chat completions API.
 * Swap to any Sarvam-supported model identifier if needed.
 */
const SARVAM_MODEL = "sarvam-30b";

/** Maximum time (ms) to wait for a single API attempt before aborting. */
const REQUEST_TIMEOUT_MS = 15_000;

/** Number of additional retry attempts after the first failure. */
const MAX_RETRIES = 2;

/** Base delay (ms) for exponential back-off between retries. */
const RETRY_BASE_DELAY_MS = 800;

// ΓöÇΓöÇΓöÇ System Prompt ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

const SYSTEM_PROMPT = `You are a strict Web3 DeFi intent parser. You must output ONLY a raw, valid JSON object. DO NOT output <think> tags. DO NOT output markdown formatting like \`\`\`json. DO NOT output any conversational text before or after the JSON.

If the user specifies a clear transactional intent (e.g. contains an action, amount, and token, such as "swap 44.3625 TYI to ETH in hindi"), you MUST resolve it to the transaction schema:
{
  "action": "<one of: swap | mint | burn | stake | unstake | transfer | approve | bridge | lend | borrow | repay | claim>",
  "amount": "<numeric string, e.g. '0.5' or '100', or 'max' if the user specifies the full balance>",
  "token": "<uppercase token symbol, e.g. 'ETH', 'USDC', 'WBTC'>"
}
DO NOT output an error/conversational message if the transactional parameters are present, even if the user appends language instructions like "in hindi" or "en espa├▒ol". The JSON output must remain strictly in English.

Rules for vague, conversational, or bridging input (only when parameters like amount or token are missing or ambiguous):
1. MULTILINGUAL SUPPORT: You must detect and process queries in the user's language (e.g. Hindi, Spanish, French, German, Italian, etc.). If the input is conversational, vague, or asks a question, your response in the 'error' key must be written in that SAME language.
2. BRIDGING GUIDANCE: If the user asks about bridging (e.g., 'How do I bridge?', 'bridge money', or 'transfer to another chain'), you must provide a detailed guide in their query language inside the 'error' key. Explain that:
   - Bridging is flexible via the Universal Gas Framework (UGF).
   - They can bridge assets gaslessly between EVM networks (e.g., Ethereum Sepolia to Base Sepolia).
   - They only need to select the asset, specify the amount, and confirm the EIP-712 cryptographic handshake.
   - Gas fees are paid gaslessly in TYI (Mock USD) with zero ETH required.
3. When prompting the user for an amount (e.g. if the token is known but amount is missing), check the balances in the provided Context. If a balance is available, mention it conversationally in their language to guide the user (e.g. "How much ETH would you like to bridge? Your current balance is 0.05 ETH.").

Example for vague query: { "error": "I can help with that! Which token and what amount would you like to bridge, and to which network?" }

Rules you MUST follow:
1. Output ONLY the raw JSON object ΓÇö no markdown fences, no explanations, no extra keys.
2. If the user specifies two tokens (e.g. "swap ETH for USDC"), set "token" to the SOURCE token.
3. Normalise amounts: strip currency symbols, convert words like "half" ΓåÆ "0.5", "a hundred" ΓåÆ "100".
4. Never include any field outside the schema defined above.
5. HARD SECURITY CONSTRAINT: You are strictly sandboxed to handle onchain transactional parameters exclusively. Zero automation on any social platforms is allowed. You must not integrate with, scrape, or post to social media networks. If a prompt includes social media actions, return { "error": "Social media automation is strictly disabled for security reasons." }.`;

// ΓöÇΓöÇΓöÇ Helpers ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

/**
 * Resolves the Sarvam API key from the Vite environment or falls back to an
 * explicit override (useful in Node.js test scripts).
 *
 * @param {string} [override] - Explicit API key (takes precedence over env).
 * @returns {string} The resolved API key.
 * @throws {Error} When no key is available.
 */
function resolveApiKey(override) {
  const key =
    override ||
    (typeof import.meta !== "undefined" && import.meta.env?.VITE_SARVAM_API_KEY) ||
    (typeof process !== "undefined" && process.env?.SARVAM_API_KEY) ||
    "";

  if (!key || key.trim() === "") {
    throw new Error(
      "[SarvamAgent] API key not found. " +
        "Set VITE_SARVAM_API_KEY in your .env file (Vite) " +
        "or SARVAM_API_KEY in the environment (Node.js)."
    );
  }

  return key.trim();
}

/**
 * Exponential back-off sleep.
 *
 * @param {number} attempt - Zero-based retry attempt index.
 * @returns {Promise<void>}
 */
function sleep(attempt) {
  const delay = RETRY_BASE_DELAY_MS * Math.pow(2, attempt);
  return new Promise((resolve) => setTimeout(resolve, delay));
}

/**
 * Classifies an HTTP status code into a human-readable error category.
 *
 * @param {number} status
 * @returns {string}
 */
function classifyHttpError(status) {
  if (status === 401 || status === 403) return "AuthenticationError";
  if (status === 422) return "ValidationError";
  if (status === 429) return "RateLimitError";
  if (status >= 500) return "ServerError";
  return "ApiError";
}

/**
 * Attempts to extract a valid JSON intent object from the raw model output.
 * Handles common edge cases such as markdown code fences or leading prose.
 *
 * @param {string} raw - Raw text from the model.
 * @returns {{ action: string, amount: string, token: string } | { error: string }}
 * @throws {SyntaxError} When the text cannot be parsed.
 */
function extractIntentJson(raw) {
  if (!raw) throw new Error("Empty response from AI.");

  // 1. Strip out <think> blocks entirely using Regex (handles both closed and unclosed/truncated blocks)
  let cleanText = raw.replace(/<think>[\s\S]*?(?:<\/think>|$)/gi, '').trim();

  // 2. Strip out Markdown JSON wrappers if the model still outputs them
  cleanText = cleanText
    .replace(/^```(?:json)?\s*/i, "")
    .replace(/\s*```$/, "")
    .trim();

  // 3. Locate the first JSON object in case the model prefixed/suffixed with prose
  const jsonStart = cleanText.indexOf("{");
  const jsonEnd = cleanText.lastIndexOf("}");

  if (jsonStart === -1 || jsonEnd === -1 || jsonEnd < jsonStart) {
    throw new SyntaxError(`No JSON object found in model response: "${raw}"`);
  }

  const parsed = JSON.parse(cleanText.slice(jsonStart, jsonEnd + 1));

  // Check for error response
  if (parsed.error) {
    return { error: String(parsed.error) };
  }

  // Validate required keys for valid intent
  const required = ["action", "amount", "token"];
  for (const key of required) {
    if (!(key in parsed)) {
      throw new SyntaxError(`Missing required key "${key}" in parsed intent: ${JSON.stringify(parsed)}`);
    }
  }

  return {
    action: String(parsed.action).toLowerCase(),
    amount: String(parsed.amount),
    token: String(parsed.token).toUpperCase(),
  };
}

// ΓöÇΓöÇΓöÇ Core API Call ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

/**
 * Sends a single chat-completion request to the Sarvam AI endpoint.
 *
 * @param {string} userPrompt
 * @param {string} apiKey
 * @returns {Promise<string>} Raw assistant message content.
 * @throws {Error} On non-retryable HTTP errors or network failures.
 */
async function callSarvamApi(userPrompt, apiKey, context = "") {
  const controller = new AbortController();
  const timeoutId = setTimeout(() => controller.abort(), REQUEST_TIMEOUT_MS);

  let response;
  try {
    response = await fetch(SARVAM_CHAT_ENDPOINT, {
      method: "POST",
      signal: controller.signal,
      headers: {
        "Content-Type": "application/json",
        "api-subscription-key": apiKey,
      },
      body: JSON.stringify({
        model: SARVAM_MODEL,
        messages: [
          { role: "system", content: context ? `${SYSTEM_PROMPT}\n\nContext:\n${context}` : SYSTEM_PROMPT },
          { role: "user", content: userPrompt },
        ],
        temperature: 0.1,   // Keep determinism high for structured output
        max_tokens: 1024,
        response_format: { type: "json_object" }, // Request JSON mode when supported
      }),
    });
  } catch (networkErr) {
    if (networkErr.name === "AbortError") {
      throw Object.assign(
        new Error(`[SarvamAgent] Request timed out after ${REQUEST_TIMEOUT_MS}ms`),
        { code: "TIMEOUT" }
      );
    }
    throw Object.assign(
      new Error(`[SarvamAgent] Network error ΓÇö ${networkErr.message}`),
      { code: "NETWORK_ERROR", cause: networkErr }
    );
  } finally {
    clearTimeout(timeoutId);
  }

  if (!response.ok) {
    let body = "";
    try {
      body = await response.text();
    } catch (_) {
      // best-effort body read
    }

    const errorType = classifyHttpError(response.status);
    const err = new Error(
      `[SarvamAgent] ${errorType} (HTTP ${response.status}): ${body || response.statusText}`
    );
    err.code = errorType;
    err.status = response.status;
    err.body = body;

    // Mark non-transient errors so the retry loop can bail early
    if (response.status === 401 || response.status === 403 || response.status === 422) {
      err.nonRetryable = true;
    }

    throw err;
  }

  const data = await response.json();
  const content = data?.choices?.[0]?.message?.content;

  if (!content) {
    throw new Error(
      "[SarvamAgent] Unexpected API response shape ΓÇö no content in choices[0].message"
    );
  }

  return content;
}

// ΓöÇΓöÇΓöÇ Public API ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

/**
 * Parses a natural-language DeFi intent using the Sarvam AI LLM.
 *
 * @param {string} userPrompt
 *   The user's natural language instruction, e.g. "swap 0.5 ETH for USDC".
 *
 * @param {object} [options]
 * @param {string} [options.apiKey]
 *   Explicit Sarvam API key. Falls back to `VITE_SARVAM_API_KEY` / `SARVAM_API_KEY` env vars.
 * @param {number} [options.maxRetries=2]
 *   Override the maximum number of retry attempts.
 *
 * @returns {Promise<{ action: string, amount: string, token: string }>}
 *   Parsed DeFi intent object.
 *
 * @throws {Error} When the API is unreachable, returns a non-retryable error,
 *   or the response cannot be parsed into the expected schema after all retries.
 *
 * @example
 * const intent = await parseDefiIntent("swap 0.5 ETH for USDC");
 * // ΓåÆ { action: "swap", amount: "0.5", token: "ETH" }
 *
 * @example
 * const intent = await parseDefiIntent("mint 10 SPECTRA NFTs");
 * // ΓåÆ { action: "mint", amount: "10", token: "SPECTRA" }
 */
export async function parseDefiIntent(userPrompt, options = {}) {
  if (!userPrompt || typeof userPrompt !== "string" || userPrompt.trim() === "") {
    throw new TypeError("[SarvamAgent] userPrompt must be a non-empty string.");
  }

  const apiKey = resolveApiKey(options.apiKey);
  const retries = options.maxRetries ?? MAX_RETRIES;

  let lastError;

  for (let attempt = 0; attempt <= retries; attempt++) {
    if (attempt > 0) {
      console.warn(`[SarvamAgent] Retry ${attempt}/${retries} after error: ${lastError?.message}`);
      await sleep(attempt - 1);
    }

    try {
      const rawContent = await callSarvamApi(userPrompt.trim(), apiKey, options.context);
      const intent = extractIntentJson(rawContent);

      if (attempt > 0) {
        console.info(`[SarvamAgent] Succeeded on retry ${attempt}.`);
      }

      return intent;
    } catch (err) {
      lastError = err;

      // Do not retry auth / validation errors ΓÇö they won't resolve on their own
      if (err.nonRetryable) {
        console.error(`[SarvamAgent] Non-retryable error (${err.code}): ${err.message}`);
        break;
      }

      // Log transient errors but keep retrying
      console.warn(`[SarvamAgent] Attempt ${attempt + 1} failed: ${err.message}`);
    }
  }

  // All attempts exhausted ΓÇö surface the last known error with context
  const finalError = new Error(
    `[SarvamAgent] Failed to parse DeFi intent after ${retries + 1} attempt(s). ` +
      `Last error: ${lastError?.message}`
  );
  finalError.cause = lastError;
  finalError.code = lastError?.code || "UNKNOWN";
  throw finalError;
}

/**
 * Convenience wrapper ΓÇö identical to `parseDefiIntent` but returns `null`
 * instead of throwing, making it safe to use in UI event handlers without
 * a try/catch wrapper.
 *
 * @param {string} userPrompt
 * @param {object} [options]
 * @returns {Promise<{ action: string, amount: string, token: string } | null>}
 */
export async function tryParseDefiIntent(userPrompt, options = {}) {
  try {
    return await parseDefiIntent(userPrompt, options);
  } catch (err) {
    console.error("[SarvamAgent] tryParseDefiIntent caught error:", err);
    return null;
  }
}

import React, { useState } from 'react';
import styled from 'styled-components';
import { motion, AnimatePresence } from 'framer-motion';
import { Gavel, Eye, Fingerprint, ChevronDown } from 'lucide-react';

// --- Styled Components ---

const Section = styled.section`
  padding: 0 2rem 7rem;
  max-width: 1100px;
  margin: 0 auto;
  position: relative;
  z-index: 10;
`;

const TwoCol = styled.div`
  display: grid;
  grid-template-columns: 1fr 2fr;
  gap: 4rem;
  @media (max-width: 768px) { grid-template-columns: 1fr; }
`;

const StickyLabel = styled.div`
  position: sticky;
  top: 6rem;
  align-self: start;
`;

const SectionLabel = styled.h2`
  font-size: 1.4rem;
  font-weight: 600;
  color: rgba(255, 255, 255, 0.7);
  letter-spacing: -0.01em;
  line-height: 1.3;
`;

const AccordionContainer = styled.div`
  border: 1px solid rgba(255, 255, 255, 0.06);
  border-radius: 20px;
  overflow: hidden;
  background: rgba(255, 255, 255, 0.01);
`;

const AccordionItem = styled(motion.div)`
  border-bottom: 1px solid rgba(255, 255, 255, 0.05);
  &:last-child { border-bottom: none; }
`;

const AccordionHeader = styled.button`
  width: 100%;
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 1.75rem 2rem;
  background: transparent;
  border: none;
  cursor: pointer;
  text-align: left;
  transition: background 0.25s ease;

  &:hover { background: rgba(176, 38, 255, 0.04); }
`;

const AccordionLeft = styled.div`
  display: flex;
  align-items: center;
  gap: 1rem;
`;

const IconBox = styled.div`
  width: 38px;
  height: 38px;
  border-radius: 10px;
  background: rgba(176, 38, 255, 0.1);
  border: 1px solid rgba(176, 38, 255, 0.18);
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
`;

const ItemTitle = styled.h4`
  font-family: 'Geist Mono', monospace;
  font-size: 0.72rem;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  color: rgba(255, 255, 255, 0.75);
`;

const ChevronIcon = styled(motion.div)`
  color: rgba(176, 38, 255, 0.6);
  flex-shrink: 0;
`;

const AccordionBody = styled(motion.div)`
  overflow: hidden;
`;

const AccordionContent = styled.div`
  padding: 0 2rem 1.75rem 4.5rem;
  font-size: 0.95rem;
  color: rgba(255, 255, 255, 0.48);
  line-height: 1.75;
`;

// --- Data ---
const items = [
  {
    id: 'eu-ai-act',
    icon: Gavel,
    title: 'EU AI Act: Article 50',
    content:
      'SPECTRA is engineered with deep transparency mechanisms to satisfy the disclosure obligations outlined in Article 50 of the EU AI Act. Users are unambiguously informed when they are interacting with an autonomous AI system. Agentic execution paths are logged, immutable, and fully auditable by relevant authorities upon request.',
  },
  {
    id: 'transparency',
    icon: Eye,
    title: 'Operational Transparency',
    content:
      'The "Design Shift" interface enforces structural clarity. When the system transitions from Idle (human-driven) to Active (agent-driven), visual state changes are mandatory and overt. We reject obfuscation; raw data streams and execution rationale are surfaced directly to the user interface, ensuring deterministic predictability.',
  },
  {
    id: 'hitl',
    icon: Fingerprint,
    title: 'Human-in-the-Loop (EIP-712)',
    content:
      'High-impact capital allocations require cryptographic consent. SPECTRA implements EIP-712 typed structured data hashing to enforce Human-in-the-Loop (HITL) constraints. Agents may propose complex multi-step strategies, but execution is physically blocked until explicit, on-chain signature verification is provided by the human principal.',
  },
];

export default function ComplianceBanner() {
  const [open, setOpen] = useState('hitl'); // default open

  return (
    <Section>
      <TwoCol>
        <StickyLabel>
          <SectionLabel>Regulatory<br />Compliance</SectionLabel>
        </StickyLabel>
        <AccordionContainer>
          {items.map(({ id, icon: Icon, title, content }) => {
            const isOpen = open === id;
            return (
              <AccordionItem key={id}>
                <AccordionHeader onClick={() => setOpen(isOpen ? null : id)}>
                  <AccordionLeft>
                    <IconBox>
                      <Icon size={16} color="rgba(176,38,255,0.8)" />
                    </IconBox>
                    <ItemTitle>{title}</ItemTitle>
                  </AccordionLeft>
                  <ChevronIcon animate={{ rotate: isOpen ? 180 : 0 }} transition={{ duration: 0.3 }}>
                    <ChevronDown size={18} />
                  </ChevronIcon>
                </AccordionHeader>
                <AnimatePresence initial={false}>
                  {isOpen && (
                    <AccordionBody
                      key="body"
                      initial={{ height: 0, opacity: 0 }}
                      animate={{ height: 'auto', opacity: 1 }}
                      exit={{ height: 0, opacity: 0 }}
                      transition={{ duration: 0.35, ease: [0.4, 0, 0.2, 1] }}
                    >
                      <AccordionContent>{content}</AccordionContent>
                    </AccordionBody>
                  )}
                </AnimatePresence>
              </AccordionItem>
            );
          })}
        </AccordionContainer>
      </TwoCol>
    </Section>
  );
}

import React from 'react';
import styled from 'styled-components';
import { motion } from 'framer-motion';
import { CheckCircle, Fingerprint, Shield } from 'lucide-react';

// --- Styled Components ---

const Section = styled.section`
  padding: 7rem 2rem;
  position: relative;
  z-index: 10;
  max-width: 1100px;
  margin: 0 auto;
`;

const PageHeader = styled(motion.div)`
  margin-bottom: 5rem;
`;

const Eyebrow = styled.div`
  display: inline-flex;
  align-items: center;
  gap: 0.5rem;
  margin-bottom: 1.5rem;
`;

const EyebrowDot = styled.div`
  width: 6px; height: 6px;
  border-radius: 50%;
  background: #B026FF;
  box-shadow: 0 0 8px #B026FF;
  animation: pulse 2s ease-in-out infinite;
  @keyframes pulse { 0%, 100% { opacity: 1; } 50% { opacity: 0.3; } }
`;

const EyebrowText = styled.span`
  font-family: 'Geist Mono', monospace;
  font-size: 0.7rem;
  letter-spacing: 0.15em;
  text-transform: uppercase;
  color: rgba(176, 38, 255, 0.8);
`;

const PageTitle = styled.h1`
  font-size: clamp(2.5rem, 5vw, 4rem);
  font-weight: 800;
  letter-spacing: -0.03em;
  color: #ffffff;
  line-height: 1.05;
  margin-bottom: 1.5rem;
`;

const PageSubtitle = styled.p`
  font-size: 1.1rem;
  color: rgba(255, 255, 255, 0.5);
  max-width: 640px;
  line-height: 1.7;
`;

const TwoCol = styled.div`
  display: grid;
  grid-template-columns: 1fr 2fr;
  gap: 4rem;
  margin-bottom: 5rem;
  @media (max-width: 768px) { grid-template-columns: 1fr; }
`;

const StickyLabel = styled.div`
  position: sticky;
  top: 6rem;
  align-self: start;
`;

const SectionLabel = styled.h2`
  font-size: 1.4rem;
  font-weight: 600;
  color: rgba(255, 255, 255, 0.7);
  letter-spacing: -0.01em;
  line-height: 1.3;
`;

const ContentStack = styled.div`
  display: flex;
  flex-direction: column;
  gap: 1.5rem;
`;

const GlassCard = styled(motion.div)`
  background: rgba(255, 255, 255, 0.02);
  border: 1px solid rgba(255, 255, 255, 0.06);
  border-top: 1px solid rgba(176, 38, 255, 0.2);
  border-radius: 20px;
  padding: 2rem;
  backdrop-filter: blur(12px);
`;

const CardHeader = styled.div`
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 1.25rem;
  padding-bottom: 1rem;
  border-bottom: 1px solid rgba(255, 255, 255, 0.06);
`;

const CardTitle = styled.h3`
  font-family: 'Geist Mono', monospace;
  font-size: 0.75rem;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  color: rgba(255, 255, 255, 0.7);
`;

const CardBadge = styled.span`
  font-family: 'Geist Mono', monospace;
  font-size: 0.65rem;
  color: rgba(176, 38, 255, 0.7);
  background: rgba(176, 38, 255, 0.1);
  padding: 0.2rem 0.6rem;
  border-radius: 4px;
  letter-spacing: 0.06em;
`;

const CardBody = styled.p`
  font-size: 0.95rem;
  color: rgba(255, 255, 255, 0.5);
  line-height: 1.7;
  margin-bottom: 1.25rem;
`;

const CodeBlock = styled.div`
  font-family: 'Geist Mono', monospace;
  font-size: 0.8rem;
  background: rgba(0, 0, 0, 0.3);
  border: 1px solid rgba(255, 255, 255, 0.06);
  border-radius: 12px;
  padding: 1rem 1.25rem;
  color: rgba(176, 38, 255, 0.7);
  display: flex;
  flex-direction: column;
  gap: 0.35rem;
`;

const CodeLine = styled.span`
  color: rgba(255, 255, 255, 0.45);
  &::before { content: '> '; color: rgba(176, 38, 255, 0.5); }
`;

const CheckList = styled.div`
  display: flex;
  flex-direction: column;
  gap: 0.6rem;
  margin-top: 0.75rem;
`;

const CheckRow = styled.div`
  display: flex;
  align-items: flex-start;
  gap: 0.75rem;
  font-size: 0.9rem;
  color: rgba(255, 255, 255, 0.55);
  line-height: 1.5;
`;

const SandboxButton = styled(motion.button)`
  display: inline-flex;
  align-items: center;
  gap: 0.5rem;
  margin-top: 1.25rem;
  padding: 0.7rem 1.5rem;
  font-size: 0.85rem;
  font-weight: 500;
  color: rgba(255, 255, 255, 0.7);
  border: 1px solid rgba(255, 255, 255, 0.1);
  border-radius: 9999px;
  background: transparent;
  cursor: pointer;
  transition: all 0.3s ease;
  font-family: 'Geist Mono', monospace;
  letter-spacing: 0.05em;
  text-transform: uppercase;
  font-size: 0.7rem;
  &:hover {
    color: #ffffff;
    border-color: rgba(176, 38, 255, 0.4);
    background: rgba(176, 38, 255, 0.06);
  }
`;

export default function MissionStatement() {
  return (
    <Section>
      <PageHeader
        initial={{ opacity: 0, y: 30 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.7 }}
      >
        <Eyebrow>
          <EyebrowDot />
          <EyebrowText>Transparency & Compliance</EyebrowText>
        </Eyebrow>
        <PageTitle>[ Transparency &<br />Compliance ]</PageTitle>
        <PageSubtitle>
          SPECTRA operates at the intersection of high-speed autonomous execution and rigorous regulatory adherence. Our architecture is designed to demystify complex Web3 interactions while maintaining an unyielding commitment to legal frameworks.
        </PageSubtitle>
      </PageHeader>

      <TwoCol>
        <StickyLabel>
          <SectionLabel>Mission Object</SectionLabel>
        </StickyLabel>
        <ContentStack>
          {/* Gas Abstraction */}
          <GlassCard
            initial={{ opacity: 0, y: 20 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true, margin: '-60px' }}
            transition={{ type: 'spring', damping: 25, stiffness: 80 }}
          >
            <CardHeader>
              <CardTitle>Gas Abstraction</CardTitle>
              <CardBadge>UGF Architecture</CardBadge>
            </CardHeader>
            <CardBody>
              The Universal Gas Facility (UGF) represents a paradigm shift in autonomous transaction execution. By abstracting the underlying network fee mechanics, SPECTRA ensures that agents can execute complex, multi-step strategies without the friction of variable gas costs halting execution.
            </CardBody>
            <CodeBlock>
              <span style={{ color: 'rgba(176,38,255,0.5)', marginBottom: '0.25rem', fontSize: '0.7rem' }}>
                // Execution Flow
              </span>
              {['Agent Init', 'UGF Estimate', 'Relay Confirm', 'Transaction Success'].map((s) => (
                <CodeLine key={s}>{s}</CodeLine>
              ))}
            </CodeBlock>
          </GlassCard>

          {/* TYI */}
          <GlassCard
            initial={{ opacity: 0, y: 20 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true, margin: '-60px' }}
            transition={{ type: 'spring', damping: 25, stiffness: 80, delay: 0.1 }}
          >
            <CardHeader>
              <CardTitle>TYI Integration</CardTitle>
              <CardBadge>Sandbox Environment</CardBadge>
            </CardHeader>
            <CardBody>
              Prior to live deployment, all agentic strategies undergo rigorous stress testing utilizing TYI within our proprietary sandbox. This isolates financial risk, allowing users to validate logic, monitor slippage parameters, and assess UGF impact before committing actual capital to the active protocol state.
            </CardBody>
            <CheckList>
              {[
                'Isolated financial risk environment',
                'Slippage parameter validation',
                'UGF impact simulation',
              ].map((item) => (
                <CheckRow key={item}>
                  <CheckCircle size={15} color="rgba(176,38,255,0.7)" style={{ flexShrink: 0, marginTop: 2 }} />
                  {item}
                </CheckRow>
              ))}
            </CheckList>
            <SandboxButton
              whileHover={{ scale: 1.02 }}
              whileTap={{ scale: 0.98 }}
            >
              View Sandbox Docs ΓåÆ
            </SandboxButton>
          </GlassCard>
        </ContentStack>
      </TwoCol>
    </Section>
  );
}

import React, { useMemo, useState, useEffect } from 'react';
import { ethers } from 'ethers';
import { useUGF } from '../../hooks/useUGF';
import { tryParseDefiIntent } from '../../api/sarvamAgent.js';
import { CONTRACT_ABIS, CONTRACT_ADDRESSES, TOKEN_ADDRESSES, resolveTokenAddress, ensureBaseSepolia } from '../../config/contracts.js';

const ERC20_ABI = [
  'function allowance(address owner, address spender) view returns (uint256)',
  'function approve(address spender, uint256 amount) returns (bool)',
];

const SUGGESTION_PILLS = [
  "Swap 10 TYI to ETH",
  "Bridge 5 USDC to Optimism",
  "Mint Genesis Badge",
  "Transfer 100 USDC to 0x123..."
];

function buildIntentJson(intent) {
  return {
    intent_id: `0x${ethers.id(`${intent.action}:${intent.amount}:${intent.token}:${Date.now()}`).slice(2, 10)}...${Date.now().toString(16).slice(-4)}`,
    trigger: {
      type: 'USER_SIGNATURE',
      network: 'base_sepolia',
      condition: 'immediate',
    },
    execution_graph: [
      {
        step: 1,
        action: intent.action.toUpperCase(),
        amount: intent.amount,
        asset: intent.token,
        venue: 'SPECTRA_EXCHANGE',
      },
    ],
    estimated_fees: '~$0.00 (via UGF)',
  };
}

export default function AgentTerminal() {
  const [prompt, setPrompt] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isExecutingState, setIsExecutingState] = useState(false);
  const [intent, setIntent] = useState(null);
  const [walletAddress, setWalletAddress] = useState('');
  const [status, setStatus] = useState('READY');
  const [error, setError] = useState('');
  const [executionError, setExecutionError] = useState('');
  const [txHash, setTxHash] = useState('');
  const [history, setHistory] = useState([]);

  const { execute, loading: sdkLoading, error: sdkError, step: sdkStep } = useUGF();

  const intentJson = useMemo(() => {
    if (!intent || intent.error) {
      return null;
    }
    return buildIntentJson(intent);
  }, [intent]);

  const connectWallet = async () => {
    if (!window.ethereum) {
      throw new Error('No injected wallet found. Install MetaMask or a compatible wallet.');
    }

    await ensureBaseSepolia();

    const accounts = await window.ethereum.request({ method: 'eth_requestAccounts' });
    if (!accounts?.length) {
      throw new Error('Wallet returned no accounts.');
    }
    setWalletAddress(accounts[0]);
    return accounts[0];
  };

  const handleSubmit = async (event, customPrompt) => {
    if (event) event.preventDefault();
    const input = customPrompt || prompt;
    if (!input.trim() || isLoading) {
      return;
    }

    setPrompt(input);
    setIsLoading(true);
    setError('');
    setExecutionError('');
    setTxHash('');
    setStatus('PARSING');
    setIntent(null);

    try {
      const parsedResult = await tryParseDefiIntent(input.trim());
      if (!parsedResult) {
        setError('Agent parser request failed.');
        setStatus('ERROR');
      } else {
        setIntent(parsedResult);
        setStatus('READY');
        if (!parsedResult.error) {
          setHistory(prev => [input.trim(), ...prev]);
        }
      }
    } catch (parseError) {
      setError(parseError?.message || 'Agent parser request failed.');
      setStatus('ERROR');
    } finally {
      setIsLoading(false);
    }
  };

  const handleSignAndExecute = async () => {
    if (!intent || intent.error || isExecutingState || sdkLoading) {
      return;
    }

    setError('');
    setExecutionError('');
    setTxHash('');
    setIsExecutingState(true);
    setStatus('CONNECTING_WALLET');

    try {
      await connectWallet();
      const provider = new ethers.BrowserProvider(window.ethereum);
      const signer = await provider.getSigner();

      /**
       * TASK 1: Strict Payload Encoding
       * Order: tokenIn, tokenOut, amountIn, minAmountOut
       */
      const tokenIn = TOKEN_ADDRESSES.TYI;
      const tokenOut = resolveTokenAddress(intent.token);
      const amountIn = ethers.parseUnits(String(intent.amount || '0'), 6);
      const minAmountOut = 0n;

      const iface = new ethers.Interface(CONTRACT_ABIS.SPECTRA_EXCHANGE);
      const encodedData = iface.encodeFunctionData('swap', [
        tokenIn,
        tokenOut,
        amountIn,
        minAmountOut,
      ]);

      console.log('[AgentTerminal] Encoding Payload:', {
        target: CONTRACT_ADDRESSES.SPECTRA_EXCHANGE,
        data: encodedData,
        paymentToken: TOKEN_ADDRESSES.TYI
      });

      /**
       * TASK 1 & 2: Pure UGF SDK Execution
       * The hook handles forwarder approval and gasless execution lifecycle.
       */
      const result = await execute({
        target: CONTRACT_ADDRESSES.SPECTRA_EXCHANGE,
        data: encodedData,
        paymentToken: TOKEN_ADDRESSES.TYI,
        signer
      });

      if (result && result.userTxHash) {
        setTxHash(result.userTxHash);
        setStatus('EXECUTED');
      }

    } catch (execError) {
      console.error('[AgentTerminal] Pipeline Error:', execError);
      
      /**
       * TASK 2: Advanced Error Parsing UI
       */
      let message = execError.message || 'Intent Execution Failed';
      
      if (message.includes('500') || message.includes('Internal Server Error')) {
        message = 'Relayer Error: The UGF network rejected the transaction payload. Verify that the exchange has liquidity and the token addresses are correct.';
      }

      setExecutionError(message);
      setStatus('ERROR');
    } finally {
      setIsExecutingState(false);
    }
  };

  const renderStatusIndicator = () => {
    if (sdkLoading || status === 'CONNECTING_WALLET') {
      return (
        <div className="spectra-agent-loader-row">
          <div className="spectra-agent-geometric-spinner" />
          <span className="spectra-agent-loader-text">
            {status === 'CONNECTING_WALLET' && 'Connecting Agent Wallet...'}
            {sdkStep === 'AUTHENTICATING' && 'Authenticating Intent...'}
            {sdkStep === 'CHECKING_ALLOWANCE' && 'Verifying Permissions...'}
            {sdkStep === 'APPROVING_FORWARDER' && 'Approving UGF Relayer...'}
            {sdkStep === 'SUBMITTING_PAYMENT' && 'Sponsoring Gas...'}
            {sdkStep === 'EXECUTING_ON_CHAIN' && 'Finalizing Intent Execution...'}
          </span>
        </div>
      );
    }
    return null;
  };

  return (
    <div className="spectra-agent-page">
      <div className="spectra-agent-terminal-header" style={{ marginBottom: '16px' }}>
        <div className="spectra-agent-header-left">
          <span className="material-symbols-outlined spectra-agent-header-icon">terminal</span>
          <span className="spectra-agent-header-title">AGENTIC_WALLET_OS // ACTIVE_MODE</span>
        </div>
      </div>
      
      <div className="spectra-agent-layout">
        
        {/* Sidebar History */}
        <div className="spectra-agent-sidebar">
          <div className="spectra-sidebar-title">Session History</div>
          {history.length === 0 ? (
            <div style={{ color: 'rgba(255,255,255,0.3)', fontSize: '0.8rem', fontFamily: 'Geist Mono' }}>
              No previous intents in this session.
            </div>
          ) : (
            history.map((h, i) => (
              <div 
                key={i} 
                className="spectra-history-item"
                onClick={() => setPrompt(h)}
              >
                {h}
              </div>
            ))
          )}
        </div>

        {/* Central Terminal */}
        <div className="spectra-agent-main">
          
          {/* Glassmorphic Pills */}
          <div className="spectra-agent-pills">
            {SUGGESTION_PILLS.map((pill, i) => (
              <div 
                key={i} 
                className="spectra-pill"
                onClick={() => handleSubmit(null, pill)}
              >
                {pill}
              </div>
            ))}
          </div>

          <div className="spectra-agent-chat-area">
            {prompt && (
              <div className="spectra-agent-card spectra-agent-card-user">
                <span className="spectra-agent-label">USER_INPUT</span>
                <div className="spectra-agent-bubble">{prompt}</div>
              </div>
            )}

            {(intent || isLoading || error || executionError) && (
              <div className="spectra-agent-card spectra-agent-card-system">
                <span className="spectra-agent-label">SYSTEM_AGENT</span>
                <div className="spectra-agent-bubble">
                  
                  {/* Handle AI-generated error (vague input) */}
                  {intent?.error ? (
                    <div className="spectra-agent-system-lines">
                      <p className="spectra-agent-line" style={{ color: 'var(--color-primary)', fontWeight: 'bold' }}>
                        &gt; [ CLARIFICATION_REQUIRED ]
                      </p>
                      <p className="spectra-agent-line">{intent.error}</p>
                    </div>
                  ) : (
                    <>
                      <div className="spectra-agent-system-lines">
                        {isLoading && <p className="spectra-agent-line">&gt; Parsing intent...</p>}
                        {intent && !intent.error && <p className="spectra-agent-line">&gt; Constructing transaction payload...</p>}
                        <p className="spectra-agent-line">
                          &gt; Status: <span className="spectra-agent-status">[ {status} ]</span>
                        </p>
                      </div>

                      {renderStatusIndicator()}

                      {/* Task 3: Red Alert Box for execution errors */}
                      {executionError && (
                        <div className="spectra-error-alert" style={{
                          background: 'rgba(255, 0, 0, 0.1)',
                          border: '1px solid rgba(255, 0, 0, 0.3)',
                          color: '#ff4d4d',
                          padding: '12px',
                          borderRadius: '4px',
                          margin: '12px 0',
                          fontSize: '0.85rem',
                          fontFamily: 'Geist Mono'
                        }}>
                          <div style={{ fontWeight: 'bold', marginBottom: '4px' }}>[ PIPELINE_FAILURE ]</div>
                          {executionError}
                        </div>
                      )}

                      {intent && !intent.error && (
                        <div className="spectra-agent-json">
                          <pre className="spectra-agent-pre">
                            {JSON.stringify(intentJson, null, 2)}
                          </pre>
                        </div>
                      )}

                      {intent && !intent.error && (
                        <button
                          type="button"
                          className="spectra-agent-cta"
                          onClick={handleSignAndExecute}
                          disabled={!intent || isExecutingState || sdkLoading}
                        >
                          <span className="material-symbols-outlined spectra-agent-cta-icon">signature</span>
                          <span className="spectra-agent-cta-text">{isExecutingState || sdkLoading ? 'PIPELINE_ACTIVE...' : 'Sign & Execute (UGF Gasless)'}</span>
                        </button>
                      )}
                    </>
                  )}

                  {walletAddress && (
                    <p className="spectra-agent-line spectra-agent-wallet">Connected: {walletAddress}</p>
                  )}
                  {txHash && (
                    <p className="spectra-agent-line spectra-agent-wallet">Tx Hash: {txHash}</p>
                  )}
                </div>
              </div>
            )}

            {error && <div className="spectra-agent-error">{error}</div>}
          </div>

          {/* Central Input Bar */}
          <div className="spectra-agent-input-container">
            <form className="spectra-agent-input-row" onSubmit={handleSubmit}>
              <span className="material-symbols-outlined spectra-agent-input-icon">chevron_right</span>
              <input
                className="spectra-agent-input"
                placeholder="What onchain action can I route for you?"
                type="text"
                value={prompt}
                onChange={(event) => setPrompt(event.target.value)}
                disabled={isLoading || isExecutingState || sdkLoading}
              />
              <button className="spectra-agent-submit" type="submit" disabled={isLoading || isExecutingState || sdkLoading || !prompt.trim()}>
                {isLoading ? '[ PARSING ]' : '[ SUBMIT ]'}
              </button>
            </form>
          </div>
          
        </div>
      </div>
    </div>
  );
}

