import React, { useEffect, useMemo, useState, useCallback, useRef } from 'react';

import styled, { keyframes } from 'styled-components';
import { ethers } from 'ethers';
import { tryParseDefiIntent } from '../../api/sarvamAgent.js';
import { CONTRACT_ABIS, CONTRACT_ADDRESSES, TOKEN_ADDRESSES, resolveTokenAddress, resolveTokenDecimals, resolveSacAddress } from '../../config/contracts.js';
import { swapTokens } from '../../lib/stellar/contracts/exchange';
import { useUGF } from '../../hooks/useUGF';
import { useAuth } from '../../context/AuthContext';
import { useRateLimit } from '../../context/RateLimitContext';
import { useError } from '../../context/ErrorContext';

const Card = styled.section`
  width: 100%;
  max-width: 980px;
  background: rgba(10, 10, 11, 0.65);
  border: 1px solid rgba(255, 255, 255, 0.1);
  border-radius: 20px;
  backdrop-filter: blur(16px);
  -webkit-backdrop-filter: blur(16px);
  box-shadow: 0 20px 70px rgba(176, 38, 255, 0.14);
  overflow: hidden;
  display: flex;
  flex-direction: column;
  resize: vertical;
  min-height: 400px;
  max-height: 90vh;

  &::-webkit-resizer {
    background-color: transparent;
    border-style: solid;
    border-width: 0 0 14px 14px;
    border-color: transparent transparent rgba(176, 38, 255, 0.8) transparent;
  }
`;

const Header = styled.header`
  height: 52px;
  padding: 0 16px;
  border-bottom: 1px solid rgba(255, 255, 255, 0.1);
  display: flex;
  align-items: center;
  justify-content: space-between;
`;

const HeaderTitle = styled.div`
  font-family: 'Geist', monospace;
  font-size: 11px;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  color: #ffffff;
  display: inline-flex;
  align-items: center;
  gap: 8px;
`;

const Dots = styled.div`
  display: inline-flex;
  gap: 8px;

  span {
    width: 10px;
    height: 10px;
    border-radius: 50%;
    border: 1px solid rgba(255, 255, 255, 0.35);
  }
`;

const Body = styled.div`
  flex: 1;
  min-height: 150px;
  overflow-y: auto;
  padding: 22px;
  display: flex;
  flex-direction: column;
  gap: 16px;
`;

const EmptyState = styled.div`
  border: 1px dashed rgba(255, 255, 255, 0.2);
  background: rgba(255, 255, 255, 0.02);
  color: #e5e5e5;
  font-family: 'Geist', monospace;
  font-size: 14px;
  padding: 18px;
`;

const Message = styled.div`
  align-self: ${({ $agent }) => ($agent ? 'flex-start' : 'flex-end')};
  width: min(88%, 760px);
  display: flex;
  flex-direction: column;
  gap: 6px;
`;

const MessageLabel = styled.span`
  font-family: 'Geist', monospace;
  font-size: 11px;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: #e5e5e5;
`;

const MessageBubble = styled.div`
  border: 1px solid rgba(255, 255, 255, 0.1);
  background: ${({ $agent }) => ($agent ? 'rgba(255,255,255,0.04)' : 'rgba(176,38,255,0.15)')};
  color: #ffffff;
