export default function WalletSelectorModal({ isOpen, onClose }) {
  const { connectWallet, connectStellar } = useAuth();
  const { showError } = useError();
  const [isConnecting, setIsConnecting] = useState(false);

  if (!isOpen) return null;

  const handleEvmConnect = async () => {
    setIsConnecting(true);
    try {
      await connectWallet();
      onClose();
    } catch (err) {
      showError(err.message || 'Failed to connect EVM wallet', 'Wallet Connection Failed');
    } finally {
      setIsConnecting(false);
    }
  };

  const handleStellarConnect = async () => {
    setIsConnecting(true);
    try {
      await connectStellar();
      onClose();
    } catch (err) {
      showError(err.message || 'Failed to connect Stellar wallet', 'Stellar Connection Failed');
    } finally {
      setIsConnecting(false);
    }
  };

  return (
    <AnimatePresence>
      {isOpen && (
        <Overlay
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          onClick={onClose}
        >
          <ModalContainer
            onClick={(e) => e.stopPropagation()}
            initial={{ opacity: 0, scale: 0.95, y: 20 }}
            animate={{ opacity: 1, scale: 1, y: 0 }}
            exit={{ opacity: 0, scale: 0.95, y: 20 }}
            transition={{ type: "spring", damping: 25, stiffness: 300 }}
          >
            <CloseButton onClick={onClose}>
              <X size={20} />
            </CloseButton>

            <Title>Login.</Title>

            <p style={{ margin:"2%",marginBottom:"4%", textAlign: "center" }}>
             Select your preferred network engine to authenticate.
            </p>

            <ConnectButton onClick={handleEvmConnect} disabled={isConnecting}>
              <Wallet size={18} />
              {isConnecting ? 'CONNECTING...' : 'Connect EVM (Base Sepolia)'}
            </ConnectButton>

            <ConnectButton onClick={handleStellarConnect} disabled={isConnecting}>
              <Hexagon size={18} />
              {isConnecting ? 'CONNECTING...' : 'Connect Stellar (Soroban Snap)'}
            </ConnectButton>
          </ModalContainer>
        </Overlay>
      )}
    </AnimatePresence>
  );
}

