 *   onClose  ΓÇö () => void
 *   onSelect ΓÇö ({ chain, token }) => void
 *   title    ΓÇö string (e.g. "Select Pay Asset")
 */
export default function CrossChainSelector({ isOpen, onClose, onSelect, title = 'Select Asset' }) {
  const dialogRef = useRef(null);
  const [selectedChain, setSelectedChain] = useState('all');
  const [chainSearch, setChainSearch] = useState('');
  const [tokenSearch, setTokenSearch] = useState('');

  // Drive native <dialog> open/close via ref imperatively
  useEffect(() => {
    const el = dialogRef.current;
    if (!el) return;
    if (isOpen && !el.open) {
      el.showModal();
    } else if (!isOpen && el.open) {
      el.close();
    }
  }, [isOpen]);

  // Close on backdrop click (dialog's native ::backdrop)
  useEffect(() => {
    const el = dialogRef.current;
    if (!el) return;
    const handleClick = (e) => {
      const rect = el.getBoundingClientRect();
      if (
        e.clientX < rect.left || e.clientX > rect.right ||
        e.clientY < rect.top  || e.clientY > rect.bottom
      ) {
        onClose();
      }
    };
    el.addEventListener('click', handleClick);
    return () => el.removeEventListener('click', handleClick);
  }, [onClose]);

  // Close on Escape
  useEffect(() => {
    const el = dialogRef.current;
    if (!el) return;
    const handleCancel = (e) => { e.preventDefault(); onClose(); };
    el.addEventListener('cancel', handleCancel);
    return () => el.removeEventListener('cancel', handleCancel);
  }, [onClose]);

  const filteredChains = useMemo(() =>
    CHAINS.filter(c => c.label.toLowerCase().includes(chainSearch.toLowerCase())),
  [chainSearch]);

  const filteredTokens = useMemo(() => {
    const pool = selectedChain === 'all' ? ALL_TOKENS : (CHAIN_TOKEN_MAP[selectedChain] || []);
    return pool.filter(t =>
      t.symbol.toLowerCase().includes(tokenSearch.toLowerCase()) ||
      t.label.toLowerCase().includes(tokenSearch.toLowerCase())
    );
  }, [selectedChain, tokenSearch]);

  const handleTokenClick = (token) => {
    const chain = CHAINS.find(c => c.id === selectedChain) || CHAINS[0];
    onSelect?.({ chain, token });
    onClose();
  };

  return (
    <Dialog ref={dialogRef}>
      <Header>
        <Title>{title}</Title>
        <CloseBtn onClick={onClose}><X size={16} /></CloseBtn>
      </Header>

      <Grid>
        {/* ΓöÇΓöÇ Left: Chain List ΓöÇΓöÇ */}
        <Column>
          <SearchBar>
            <Search size={14} color="#52525b" />
            <SearchInput
              placeholder="Search chains..."
              value={chainSearch}
              onChange={e => setChainSearch(e.target.value)}
            />
          </SearchBar>
          <List>
            {filteredChains.map(chain => (
              <ChainItem
                key={chain.id}
                $active={selectedChain === chain.id}
                onClick={() => { setSelectedChain(chain.id); setTokenSearch(''); }}
              >
                <ChainIcon>{chain.icon}</ChainIcon>
                {chain.label}
              </ChainItem>
            ))}
          </List>
        </Column>

        {/* ΓöÇΓöÇ Right: Token List ΓöÇΓöÇ */}
        <Column>
          <SearchBar>
            <Search size={14} color="#52525b" />
            <SearchInput
              placeholder="Search tokens..."
              value={tokenSearch}
              onChange={e => setTokenSearch(e.target.value)}
            />
          </SearchBar>
          <List>
            {filteredTokens.length === 0 ? (
              <EmptyMsg>No tokens found</EmptyMsg>
            ) : filteredTokens.map((token, i) => (
              <TokenItem key={`${token.id}-${i}`} onClick={() => handleTokenClick(token)}>
                <TokenLeft>
                  <TokenAvatar>{token.symbol.slice(0, 3)}</TokenAvatar>
                  <TokenInfo>
                    <TokenSymbol>{token.symbol}</TokenSymbol>
                    <TokenLabel>{token.label}</TokenLabel>
                  </TokenInfo>
                </TokenLeft>
                <NetworkBadge>{token.network}</NetworkBadge>
              </TokenItem>
            ))}
          </List>
        </Column>
      </Grid>
    </Dialog>
  );
}

