export default function FeedbackSection() {
  const [rating, setRating] = useState(0);
  const [hoverRating, setHoverRating] = useState(0);
  const [submitted, setSubmitted] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    designation: '',
    company: '',
    thoughts: ''
  });

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setIsSubmitting(true);
    
    try {
      // 1. Submit to Formspree (original)
      const formPromise = fetch('https://formspree.io/f/xojogwna', {
        method: 'POST',
        headers: {
          'Accept': 'application/json',
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          ...formData,
          rating: rating || 'Not rated',
        }),
      });
      
      // 2. Submit to Stellar Soroban (gasless)
      const stellarPromise = saveFeedback(
        formData.name,
        formData.email,
        formData.designation,
        formData.company,
        formData.thoughts,
        rating || 0
      ).catch(e => console.warn('Stellar save failed:', e));

      const [response] = await Promise.all([formPromise, stellarPromise]);
      
      if (response.ok) {
        setSubmitted(true);
      } else {
        alert("There was an issue submitting your feedback. Please try again.");
      }
    } catch (error) {
      console.error(error);
      alert("Network error. Please try again.");
    } finally {
      setIsSubmitting(false);
    }
  };

  if (submitted) {
    return (
      <Section id="feedback">
        <Container style={{ textAlign: 'center', padding: '64px 24px' }} className="bg-grid-overlay">
          <Title>[ FEEDBACK RECEIVED ]</Title>
          <Subtitle style={{ marginBottom: 0 }}>Thank you for helping us shape the future of Spectra.</Subtitle>
        </Container>
      </Section>
    );
  }

  return (
    <Section id="feedback">
      <Container >
        <Title>Help Us Improve</Title>
        <Subtitle>Your feedback directly shapes the future of Spectra.</Subtitle>
        
        <Form onSubmit={handleSubmit}>
          <Grid>
            <FormGroup>
              <Label>Name</Label>
              <Input type="text" name="name" value={formData.name} onChange={handleChange} required placeholder="John Doe" />
            </FormGroup>
            <FormGroup>
              <Label>Email</Label>
              <Input type="email" name="email" value={formData.email} onChange={handleChange} required placeholder="john@example.com" />
            </FormGroup>
          </Grid>
          
          <Grid>
            <FormGroup>
              <Label>Designation</Label>
              <Input type="text" name="designation" value={formData.designation} onChange={handleChange} placeholder="e.g. DeFi Trader" />
            </FormGroup>
            <FormGroup>
              <Label>Company</Label>
              <Input type="text" name="company" value={formData.company} onChange={handleChange} placeholder="Organization" />
            </FormGroup>
          </Grid>
          
          <FormGroup>
            <Label>Thoughts & Suggestions</Label>
            <TextArea name="thoughts" value={formData.thoughts} onChange={handleChange} required placeholder="How can we make Spectra better for you?" />
          </FormGroup>
          
          <FormGroup>
            <Label>Overall Experience</Label>
            <StarContainer>
              {[1, 2, 3, 4, 5].map((star) => (
                <Star
                  key={star}
                  type="button"
                  $active={star <= (hoverRating || rating)}
                  onMouseEnter={() => setHoverRating(star)}
                  onMouseLeave={() => setHoverRating(0)}
                  onClick={() => setRating(star)}
                >
                  <span className="material-symbols-outlined">star</span>
                </Star>
              ))}
            </StarContainer>
          </FormGroup>
          
          <SubmitButton type="submit" disabled={isSubmitting}>
            {isSubmitting ? 'Submitting...' : 'Submit Feedback'}
            <span className="material-symbols-outlined">send</span>
          </SubmitButton>
        </Form>
      </Container>
    </Section>
  );
}

