  return (
    <>
      <NavWrap>
      <NavInner>
        <Logo to="/">SPECTRA</Logo>

        <NavLinks>
          {NAV_LINKS.map(({ to, label }) => {
            const isActive = location.pathname === to || (to !== '/' && location.pathname.startsWith(to));
            return (
              <NavLink key={to} to={to} $active={isActive}>
                {label}
              </NavLink>
            );
          })}
