        <NavRight>
          {isLoggedIn ? (
            // Task 3: Only profile icon when authenticated ΓÇö no separate Logout in nav
            <ProfileIcon onClick={handleProfileClick} title="Go to Profile">
              <img
                src={`/profile/${userData.avatarId}.png`}
