export default function PricingMatrix({ selectedTier = 'nexus', onSelectTier }) {
  return (
    <Wrapper
      initial={{ opacity: 0, y: 20 }}
      whileInView={{ opacity: 1, y: 0 }}
      viewport={{ once: true }}
      transition={{ type: 'spring', damping: 25, stiffness: 80 }}
