import { useState, useCallback } from 'react';
import { ethers } from 'ethers';
import { UGFClient as TestnetUGFClient } from '@tychilabs/ugf-testnet-js';

/**
 * Custom hook to provide pure UGF SDK execution without manual gas simulations.
 * This satisfies the Lead Web3 Frontend Architect's mandate for headless SDK integration.
 */
export function useUGF() {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [step, setStep] = useState('IDLE');

  const getClient = useCallback(() => {
    // Using TestnetUGFClient explicitly for Base Sepolia (testnet)
    return new TestnetUGFClient();
  }, []);

  const getForwarder = useCallback(async () => {
    const client = getClient();
    const option = await client.registry.getOption('TYI_MOCK_USD');
    if (!option || !option.receiver_address) {
      throw new Error('UGF_REGISTRY_ERROR: Could not resolve Forwarder address.');
    }
    return option.receiver_address;
  }, [getClient]);

  const quote = useCallback(async ({ target, data, paymentToken, signer }) => {
    const client = getClient();
    const address = await signer.getAddress();
    const addressLower = address.toLowerCase();
    const targetLower = target.toLowerCase();
    
    // Authenticate with UGF before quoting
    await client.auth.login(signer);

    /**
     * CRITICAL FIX: The UGF Relayer requires 'from' in the tx_object to simulate the transaction.
     * We use hex '0x0' for value to be safe with some relayer parsers.
     */
    const q = await client.quote.get({
      payment_coin: 'TYI_MOCK_USD', 
      payer_address: addressLower,
      payment_chain: '84532',
      payment_chain_type: 'evm',
      tx_object: JSON.stringify({
        from: addressLower,
        to: targetLower,
        data: data || '0x',
        value: '0x0'
      }),
      dest_chain_id: '84532',
      dest_chain_type: 'evm',
    });

    return q;
  }, [getClient]);

  const execute = useCallback(async ({ target, data, paymentToken, signer }) => {
    setLoading(true);
    setError(null);
    setStep('INITIALIZING');

    try {
      const client = getClient();
      const address = await signer.getAddress();

      // 1. Auth
      setStep('AUTHENTICATING');
      await client.auth.login(signer);

      // 2. Quote
      setStep('QUOTING');
      const q = await quote({ target, data, paymentToken, signer });

      // 3. Approval Check (Targeting UGF Forwarder)
      setStep('CHECKING_ALLOWANCE');
      const forwarder = await getForwarder();
      const tokenContract = new ethers.Contract(
        paymentToken,
        [
          'function allowance(address owner, address spender) view returns (uint256)',
          'function approve(address spender, uint256 amount) returns (bool)'
        ],
        signer
      );
      
      const allowance = await tokenContract.allowance(address, forwarder);
      
      // q.payment_amount is usually the raw value as a string
      const needed = ethers.toBigInt(q.payment_amount);

      if (allowance < needed) {
        setStep('APPROVING_FORWARDER');
        const tx = await tokenContract.approve(forwarder, ethers.MaxUint256);
        await tx.wait(1);
      }

      // 4. Payment
      setStep('SUBMITTING_PAYMENT');
      // For testnet, we settle in TYI_MOCK_USD
      await client.payment.x402.execute({ quote: q, signer, token: 'TYI_MOCK_USD' });

      // 5. Execution
      setStep('EXECUTING_ON_CHAIN');
      const result = await client.chains.evm.sponsorAndExecute(
        q.digest,
        signer,
        async (s) => {
           // Return the raw transaction request - Testnet SDK handles the rest
           return {
             to: target,
             data: data || '0x',
             value: 0n
           };
        }
      );

      setStep('SUCCESS');
      setLoading(false);
      return result;

    } catch (err) {
      console.error('[useUGF] Execution Pipeline Failed:', err);
      
      let friendlyMessage = err.message || 'UGF Execution Error';
      
      // Handle Contract Reverts / CALL_EXCEPTION / HTTP 500
      if (err.message?.includes('500') || err.message?.includes('Internal Server Error')) {
        friendlyMessage = 'Relayer Error: The UGF network rejected the transaction payload. Verify that the exchange has liquidity and the token addresses are correct.';
      } else if (err.message?.includes('CALL_EXCEPTION') || err.message?.includes('execution reverted')) {
        friendlyMessage = 'Transaction Reverted by Smart Contract. Ensure the Exchange has testnet liquidity and you have not exceeded your daily SaaS tier limits.';
      } else if (err.code === 4001 || err.message?.includes('rejected')) {
        friendlyMessage = 'Transaction rejected by user.';
      }

      setError(friendlyMessage);
      setStep('ERROR');
      setLoading(false);
      throw new Error(friendlyMessage);
    }
  }, [getClient, getForwarder, quote]);

  return { execute, quote, loading, error, step };
}

import { rpc, Networks, TransactionBuilder, Contract, Keypair, xdr } from '@stellar/stellar-sdk';
import { signStellarTransaction } from './snap';
import { submitRelayedTransaction } from './relayer';

const RPC_URL = import.meta.env.VITE_STELLAR_RPC_URL || 'https://soroban-testnet.stellar.org';
const IS_TESTNET = import.meta.env.VITE_STELLAR_NETWORK !== 'mainnet';
export const networkPassphrase = IS_TESTNET ? Networks.TESTNET : Networks.PUBLIC;

export const server = new rpc.Server(RPC_URL, { allowHttp: false });

export const CONTRACTS = {
  SAAS:     import.meta.env.VITE_SAAS_CONTRACT_ID,
  PROFILE:  import.meta.env.VITE_PROFILE_CONTRACT_ID,
  EXCHANGE: import.meta.env.VITE_EXCHANGE_CONTRACT_ID,
  NFT:      import.meta.env.VITE_NFT_CONTRACT_ID,
  FEEDBACK: import.meta.env.VITE_STELLAR_FEEDBACK_CONTRACT,
  BRIDGE:   import.meta.env.VITE_STELLAR_BRIDGE_CONTRACT,
};

// ΓöÇΓöÇΓöÇ Simple read-cache: avoid repeat RPC for same key within 60s ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
const _readCache = new Map();
function _cacheKey(contractId, method, args) {
  return `${contractId}:${method}:${args.length}`;
}
function _getCached(key) {
  const entry = _readCache.get(key);
  if (!entry) return null;
  if (Date.now() - entry.ts > 60_000) { _readCache.delete(key); return null; }
  return entry.value;
}
function _setCache(key, value) {
  _readCache.set(key, { value, ts: Date.now() });
}

/**
 * Invoke a Soroban smart contract (write ΓÇö requires signing)
 */
export async function invokeContract(contractId, method, args, publicKey) {
  if (!contractId) throw new Error(`Contract ID not set for method: ${method}`);

  const contract = new Contract(contractId);
  const operation = contract.call(method, ...args);

  // 1. Get account for sequence number
  let account;
  try {
    account = await server.getAccount(publicKey);
  } catch (err) {
    if (err?.response?.status === 404 && IS_TESTNET) {
      console.warn('[Stellar] Account not found. Auto-funding via Friendbot...');
      await fetch(`https://friendbot.stellar.org/?addr=${publicKey}`);
      // Retry fetching account
      account = await server.getAccount(publicKey);
    } else {
      throw err;
    }
  }

  // 2. Build the transaction
  let tx = new TransactionBuilder(account, {
    fee: '1000',
    networkPassphrase,
  })
    .addOperation(operation)
    .setTimeout(30)
    .build();

  // 3. Simulate to get footprint + updated fee
  const simResponse = await server.simulateTransaction(tx);

  if (rpc.Api.isSimulationError(simResponse)) {
    throw new Error(`Simulation error: ${simResponse.error}`);
  }

  // 4. Assemble (inject auth + update fee) ΓÇö new SDK: only 2 args
  const assembledTx = rpc.assembleTransaction(tx, simResponse).build();

  // 5. Sign via MetaMask Stellar Snap
  const signedXdr = await signStellarTransaction(assembledTx.toXDR(), IS_TESTNET);

  // 6. Submit via relayer (gasless fee-bump transaction)
  const sendResponse = await submitRelayedTransaction(signedXdr);

  if (sendResponse.status === 'ERROR') {
    throw new Error(`Transaction rejected: ${JSON.stringify(sendResponse.errorResult)}`);
  }

  // 7. Poll until confirmed
  let statusResponse;
  for (let i = 0; i < 20; i++) {
    statusResponse = await server.getTransaction(sendResponse.hash);
    if (statusResponse.status !== rpc.Api.GetTransactionStatus.NOT_FOUND) break;
    await new Promise(r => setTimeout(r, 2000));
  }

  if (!statusResponse || statusResponse.status === rpc.Api.GetTransactionStatus.FAILED) {
    throw new Error('Transaction failed on-chain');
  }

  return statusResponse;
}

/**
 * Read from a Soroban contract (simulation only ΓÇö free, no signing, cached 60s)
 * Returns the parsed ScVal result.
 */
export async function readContract(contractId, method, args, _publicKey) {
  if (!contractId) throw new Error(`Contract ID not set for method: ${method}`);

  const cacheKey = _cacheKey(contractId, method, args);
  const cached = _getCached(cacheKey);
  if (cached) return cached;

  const contract = new Contract(contractId);
  const operation = contract.call(method, ...args);

  // For reads we only need any valid-looking account for the transaction envelope.
  // We use a random ephemeral keypair so we never need a network getAccount() call.
  const ephemeral = Keypair.random();
  const fakeAccount = {
    accountId: () => ephemeral.publicKey(),
    sequenceNumber: () => '0',
    incrementSequenceNumber: () => {},
  };

  const tx = new TransactionBuilder(fakeAccount, { fee: '100', networkPassphrase })
    .addOperation(operation)
    .setTimeout(30)
    .build();

  const simResponse = await server.simulateTransaction(tx);

  if (rpc.Api.isSimulationError(simResponse)) {
    throw new Error(`Read simulation error: ${simResponse.error}`);
  }

  const result = simResponse.result?.retval ?? null;
  _setCache(cacheKey, result);
  return result;
}

import { Address, nativeToScVal, scValToNative } from '@stellar/stellar-sdk';
import { CONTRACTS, invokeContract } from '../client';

/**
 * Initiate a gasless cross-chain bridge transfer from Soroban to EVM via Axelar GMP.
 * @param {string} publicKey - Stellar public key of the user initiating the bridge
 * @param {string} tokenAddress - Soroban Asset Contract (SAC) address to bridge
 * @param {string} amountIn - Amount of tokens (formatted for decimals)
 * @param {string} destinationChain - Name of the destination chain (e.g. "base-sepolia")
 * @param {string} destinationAddress - The target 0x... EVM address
 */
export async function bridgeToEvm(publicKey, tokenAddress, amountIn, destinationChain, destinationAddress) {
  const args = [
    new Address(publicKey).toScVal(),
    new Address(tokenAddress).toScVal(),
    nativeToScVal(BigInt(amountIn), { type: 'i128' }),
    nativeToScVal(destinationChain, { type: 'string' }),
    nativeToScVal(destinationAddress, { type: 'string' }),
  ];

  return await invokeContract(CONTRACTS.BRIDGE, 'bridge_to_evm', args, publicKey);
}

