export default function Login() {
  const { connectWallet, connectStellar, isLoggedIn, profile, isLoadingProfile, isInitialized } = useAuth();
  const [error, setError] = useState('');
  const [isConnecting, setIsConnecting] = useState(false);
  const navigate = useNavigate();

  if (!isInitialized) {
    return (
      <LoginContainer>
        <Description style={{ color: '#b026ff', letterSpacing: '0.2em', textTransform: 'uppercase' }}>INITIALIZING_SESSION...</Description>
      </LoginContainer>
    );
  }

  // If already logged in, redirect them away
  if (isLoggedIn) {
    if (isLoadingProfile) {
      return (
        <LoginContainer>
          <LoginBox>
            <Description>Syncing Profile Data...</Description>
          </LoginBox>
        </LoginContainer>
      );
    }
    if (!profile.exists) {
      return <Navigate to="/profile?mode=onboarding" replace />;
    }
    return <Navigate to="/" replace />;
  }

  const handleEvmConnect = async () => {
    setError('');
    setIsConnecting(true);
    try {
      await connectWallet();
    } catch (err) {
      setError(err.message || 'Failed to connect EVM wallet');
      setIsConnecting(false);
    }
  };

  const handleStellarConnect = async () => {
    setError('');
    setIsConnecting(true);
    try {
      await connectStellar();
    } catch (err) {
      setError(err.message || 'Failed to connect Stellar wallet');
      setIsConnecting(false);
    }
  };

  return (
    <LoginContainer>
      <LoginBox>
        <Title>Login.</Title>
        <p style={{ margin:"2%",marginBottom:"4%", textAlign: "center" }}>
             Get Started with your First Swapping Transaction, authenticate now.
            </p>
            
        <ConnectBtn onClick={handleEvmConnect} disabled={isConnecting}>
          <Wallet size={18} />
          {isConnecting ? 'CONNECTING...' : 'Connect EVM (Base Sepolia)'}
        </ConnectBtn>

        <ConnectBtn onClick={handleStellarConnect} disabled={isConnecting}>
          <Hexagon size={18} />
          {isConnecting ? 'CONNECTING...' : 'Connect Stellar (Soroban Snap)'}
        </ConnectBtn>
        
        {error && <ErrorText>{error}</ErrorText>}
      </LoginBox>
    </LoginContainer>
  );
}

